module top_module(
    input in1,
    input in2,
    input in3,
    input in4,
    input disable_inversion,
    output reg [3:0] out
);always @(*) begin
    // Concatenate the four input bits
    out = {in1, in2, in3, in4};

    // Invert the bits corresponding to in1 and in2 if disable_inversion is 1
    if (disable_inversion == 1) begin
        out[3:2] = ~out[3:2];
    end
end

endmodule
